#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to calculate the orientation of three points
int orientation(int x1, int y1, int x2, int y2, int x3, int y3) {
    int val = (y2 - y1) * (x3 - x2) - (x2 - x1) * (y3 - y2);
    if (val == 0) return 0;  // Collinear
    return (val > 0) ? 1 : 2;  // Clockwise or counterclockwise
}

// Function to check if a point is inside a convex polygon
int isInside(int x, int y, int n, int *x1, int *y1) {
    int i, j = 0;
    bool inside = false;
    for (i = 0, j = n - 1; i < n; j = i++) {
        if (((y1[i] > y) != (y1[j] > y)) && (x < (x1[j] - x1[i]) * (y - y1[i]) / (y1[j] - y1[i]) + x1[i]))
            inside = !inside;
    }
    return inside;
}

int main() {
    int N, M, Q, i, j, k, x, y, count;
    int *x1, *y1, *x2, *y2;
    scanf("%d %d", &N, &M);
    x1 = (int *)malloc(N * sizeof(int));
    y1 = (int *)malloc(N * sizeof(int));
    x2 = (int *)malloc(M * sizeof(int));
    y2 = (int *)malloc(M * sizeof(int));
    for (i = 0; i < N; i++) scanf("%d %d", &x1[i], &y1[i]);
    for (i = 0; i < M; i++) scanf("%d %d", &x2[i], &y2[i]);
    scanf("%d", &Q);
    while (Q--) {
        scanf("%d", &k);
        int *x3 = (int *)malloc(k * sizeof(int));
        int *y3 = (int *)malloc(k * sizeof(int));
        for (i = 0; i < k; i++) {
            scanf("%d", &j);
            x3[i] = x1[j - 1];
            y3[i] = y1[j - 1];
        }
        count = 0;
        for (i = 0; i < M; i++) {
            if (isInside(x2[i], y2[i], k, x3, y3)) count++;
        }
        printf("%d\n", count);
        free(x3);
        free(y3);
    }
    free(x1);
    free(y1);
    free(x2);
    free(y2);
    return 0;
}

