#include <iostream>
#include <vector>
using namespace std;

// Function to calculate the orientation of three points
int orientation(int x1, int y1, int x2, int y2, int x3, int y3) {
    int val = (y2 - y1) * (x3 - x2) - (x2 - x1) * (y3 - y2);
    if (val == 0) return 0;  // Collinear
    return (val > 0) ? 1 : 2;  // Clockwise or counterclockwise
}

// Function to check if a point is inside a convex polygon
bool isInside(int x, int y, vector<pair<int, int>> &polygon) {
    int n = polygon.size();
    bool inside = false;
    for (int i = 0, j = n - 1; i < n; j = i++) {
        if (((polygon[i].second > y) != (polygon[j].second > y)) && (x < (polygon[j].first - polygon[i].first) * (y - polygon[i].second) / (polygon[j].second - polygon[i].second) + polygon[i].first))
            inside = !inside;
    }
    return inside;
}

int main() {
    int N, M, Q, i, j, k, x, y, count;
    cin >> N >> M;
    vector<pair<int, int>> redPoints(N), blackPoints(M);
    for (i = 0; i < N; i++) cin >> redPoints[i].first >> redPoints[i].second;
    for (i = 0; i < M; i++) cin >> blackPoints[i].first >> blackPoints[i].second;
    cin >> Q;
    while (Q--) {
        cin >> k;
        vector<pair<int, int>> polygon(k);
        for (i = 0; i < k; i++) {
            cin >> j;
            polygon[i] = redPoints[j - 1];
        }
        count = 0;
        for (i = 0; i < M; i++) {
            if (isInside(blackPoints[i].first, blackPoints[i].second, polygon)) count++;
        }
        cout << count << endl;
    }
    return 0;
}

