        }
        int Q = sc.nextInt();
        while (Q-- > 0) {
            int k = sc.nextInt();
            int[] x = new int[k];
            int[] y = new int[k];
            for (int i = 0; i < k; i++) {
                int j = sc.nextInt();
                x[i] = redPoints[j - 1][0];
                y[i] = redPoints[j - 1][1];
            }
            int count = 0;
            for (int i = 0; i < M; i++) {
                if (isInside(blackPoints[i][0], blackPoints[i][1], x, y, k)) count++;
            }
            System.out.println(count);
        }
    }
    public static boolean isInside(int x, int y, int[] x1, int[] y1, int n) {
        boolean inside = false;
        for (int i = 0, j = n - 1; i < n; j = i++) {
            if (((y1[i] > y) != (y1[j] > y)) && (x < (x1[j] - x1[i]) * (y - y1[i]) / (y1[j] - y1[i]) + x1[i]))
